sys_script.script:
(function executeRule(current, previous /*null when async*/) {
    try {
        if (gs.getProperty('x_146833_idpkiro.ai.enabled', 'false') !== 'true') {
            return;
        }
        var ai = new x_146833_idpkiro.IDPAIOrchestrator();
        ai.onDeploymentFailure(current.getUniqueValue());
    } catch (e) {
        gs.logError('IDP AI deployment failure hook error: ' + e.message, 'IDP-AIHook');
    }
})(current, previous);
